fn timeoutForNanoseconds(timeout_ns: u64) Io.Timeout {
    assert(timeout_ns > 0);
    return .{ .duration = .{
        .raw = Io.Duration.fromNanoseconds(@intCast(timeout_ns)),
        .clock = .awake,
    } };
