159→        // Move any data after the 1xx headers to the beginning of the buffer.
160→        // The receiveHeaders may have read bytes belonging to the next response.
161→        const bytes_after_100 = headers.header_len - headers.header_end;
162→        if (bytes_after_100 > 0) {
163→            // Move data to beginning of buffer
164→            const src = header_buffer[headers.header_end..headers.header_len];
165→            std.mem.copyForwards(u8, header_buffer[0..bytes_after_100], src);
166→            // Zero out the rest
167→            @memset(header_buffer[bytes_after_100..], 0);
168→            pre_read_bytes = bytes_after_100;
169→        } else {
170→            // No leftover data, just clear the buffer
171→            @memset(&header_buffer, 0);
172→            pre_read_bytes = 0;
173→        }
174→    }
175→
176→    // S3: Postcondition - we exited the loop with a final status
177→    if (status < 200) {
178→        // Too many 1xx responses - treat as invalid
179→        debugLog("recv: too many 1xx responses, giving up", .{});
180→        return ForwardError.InvalidResponse;
