548→    const sock = try posix.socket(posix.AF.INET, posix.SOCK.STREAM, posix.IPPROTO.TCP);
549→    errdefer posix.close(sock);
550→
551→    const addr: posix.sockaddr.in = .{
552→        .port = std.mem.nativeToBig(u16, port),
553→        .addr = std.mem.nativeToBig(u32, LOOPBACK_IPV4_BE),
554→    };
555→    try posix.connect(sock, @ptrCast(&addr), @sizeOf(posix.sockaddr.in));
556→
557→    const recv_timeout = posix.timeval{
558→        .sec = TCP_RECV_TIMEOUT_SEC,
559→        .usec = 0,
560→    };
561→    try posix.setsockopt(sock, posix.SOL.SOCKET, posix.SO.RCVTIMEO, std.mem.asBytes(&recv_timeout));
562→
563→    return sock;
564→}
