**Step 4: Add regression tests for `responseExpectsBody` logic**

Add these tests at end of `serval-proxy/h1/response.zig` test section:

```zig
// -----------------------------------------------------------------------------
// Close-delimited response detection tests
// Regression: forwardResponse previously silently dropped body bytes for
// responses without Content-Length or chunked encoding.
// -----------------------------------------------------------------------------

test "response patterns: close-delimited detection - 204 has no body" {
    // 204 No Content never has a body, regardless of framing
    const response = "HTTP/1.1 204 No Content\r\n\r\n";
    const status = parseStatusCode(response).?;
    const cl = parseContentLength(response);
    const chunked = isChunkedResponse(response);
    // 204: no body expected, close-delimited logic should not trigger
    try testing.expectEqual(@as(u16, 204), status);
    try testing.expectEqual(@as(?u64, null), cl);
    try testing.expect(!chunked);
    // Invariant: status == 204 means no body, safe to pass through
}

test "response patterns: close-delimited detection - 304 has no body" {
    const response = "HTTP/1.1 304 Not Modified\r\n\r\n";
    const status = parseStatusCode(response).?;
    const cl = parseContentLength(response);
    const chunked = isChunkedResponse(response);
    try testing.expectEqual(@as(u16, 304), status);
    try testing.expectEqual(@as(?u64, null), cl);
    try testing.expect(!chunked);
}

test "response patterns: close-delimited detection - 200 without framing is unsafe" {
    // A 200 OK with neither Content-Length nor chunked encoding is a
    // close-delimited response. The proxy must reject this for non-HEAD
    // requests to prevent silent body truncation.
    const response = "HTTP/1.1 200 OK\r\nConnection: close\r\n\r\n";
    const status = parseStatusCode(response).?;
    const cl = parseContentLength(response);
    const chunked = isChunkedResponse(response);
    try testing.expectEqual(@as(u16, 200), status);
    try testing.expectEqual(@as(?u64, null), cl);
    try testing.expect(!chunked);
    // Invariant: status 200, not HEAD, no framing → must be rejected
    // (the actual rejection happens in forwardResponse, not testable here
    // without Io/sockets, but the detection conditions are verified)
    try testing.expect(status != 204 and status != 304);
}

test "response patterns: close-delimited detection - 200 with Content-Length is safe" {
    // If Content-Length is present, body is length-delimited, not close-delimited
    const response = "HTTP/1.1 200 OK\r\nContent-Length: 42\r\n\r\n";
    const cl = parseContentLength(response);
    try testing.expectEqual(@as(?u64, 42), cl);
}

test "response patterns: close-delimited detection - 200 with chunked is safe" {
    const response = "HTTP/1.1 200 OK\r\nTransfer-Encoding: chunked\r\n\r\n";
    const chunked = isChunkedResponse(response);
    try testing.expect(chunked);
}
```

**Step 5: Run tests**

Run: `zig build test 2>&1 | tail -5`
Expected: all tests pass, including new close-delimited detection tests

**Step 6: Commit**

```bash
git add serval-proxy/h1/response.zig serval-proxy/forwarder.zig
git commit -m "fix(proxy/h1): reject close-delimited responses fail-closed

Thread is_head_request through forwardResponse() so it can distinguish
HEAD (no body) from close-delimited (body exists but unframed). Any
body-bearing response (not HEAD, not 204/304) without Content-Length or
chunked encoding is now rejected with InvalidResponse instead of
silently dropping the body. Previously, even when pre_read_body was
empty, later body bytes would never be read."
```

