```zig
pub fn forwardResponse(
    io: Io,
    upstream_conn: *Connection,
    client_stream: Io.net.Stream,
    upstream_socket: *Socket,
    client_socket: *Socket,
    is_pooled: bool,
    is_head_request: bool,
