 1→//! Test-only POSIX I/O helpers for socket-backed ACME unit tests.
 2→
 3→const std = @import("std");
 4→const assert = std.debug.assert;
 5→const c = std.c;
 6→const posix = std.posix;
 7→
 8→pub fn create_socket_pair() ?[2]i32 {
 9→    assert(posix.AF.UNIX > 0);
10→    assert(posix.SOCK.STREAM > 0);
11→
12→    var fds: [2]i32 = undefined;
13→    const rc = c.socketpair(
14→        @intCast(posix.AF.UNIX),
15→        @intCast(posix.SOCK.STREAM),
16→        0,
17→        &fds,
18→    );
19→    if (rc != 0) return null;
20→    return fds;
21→}
