23→pub fn close_fd(fd: i32) void {
24→    assert(fd >= 0);
25→    assert(fd <= std.math.maxInt(c_int));
26→    _ = c.close(fd);
27→}
28→
29→pub fn write_bytes(fd: i32, bytes: []const u8) bool {
30→    assert(fd >= 0);
31→    assert(bytes.len <= std.math.maxInt(isize));
32→
33→    const written = c.write(fd, bytes.ptr, bytes.len);
34→    if (written < 0) return false;
35→    return written == @as(isize, @intCast(bytes.len));
36→}
