 1→// Custom test runner with verbose output
 2→// Based on https://gist.github.com/karlseguin/c6bea5b35e4e8d26af6f81c22cb5d76b
 3→// For Zig 0.15+
 4→
 5→const std = @import("std");
 6→const builtin = @import("builtin");
 7→
 8→const BORDER = "=" ** 80;
 9→
10→pub fn main() !void {
11→    var pass: usize = 0;
12→    var fail: usize = 0;
13→    var skip: usize = 0;
14→
15→    const total = builtin.test_functions.len;
16→    var test_num: usize = 0;
17→
18→    for (builtin.test_functions) |t| {
19→        test_num += 1;
20→        std.testing.allocator_instance = .{};
21→
22→        const friendly_name = extractTestName(t.name);
23→
24→        // Print test name before running
25→        std.debug.print("{d}/{d} {s}...", .{ test_num, total, friendly_name });
26→
27→        const result = t.func();
28→
29→        if (std.testing.allocator_instance.deinit() == .leak) {
30→            std.debug.print("\x1b[31mLEAK\x1b[0m\n", .{});
31→            fail += 1;
32→            continue;
33→        }
34→
35→        if (result) |_| {
36→            std.debug.print("\x1b[32mOK\x1b[0m\n", .{});
37→            pass += 1;
38→        } else |err| switch (err) {
39→            error.SkipZigTest => {
40→                std.debug.print("\x1b[33mSKIP\x1b[0m\n", .{});
41→                skip += 1;
42→            },
43→            else => {
44→                std.debug.print("\x1b[31mFAIL: {s}\x1b[0m\n", .{@errorName(err)});
45→                fail += 1;
46→                if (@errorReturnTrace()) |trace| {
47→                    std.debug.dumpStackTrace(trace);
48→                }
49→            },
50→        }
51→    }
52→
53→    std.debug.print("\n{s}\n", .{BORDER});
54→    if (fail == 0) {
55→        std.debug.print("\x1b[32mAll {d} tests passed", .{pass});
56→    } else {
57→        std.debug.print("\x1b[31m{d} of {d} tests failed", .{ fail, pass + fail });
58→    }
59→    if (skip > 0) {
60→        std.debug.print(" ({d} skipped)", .{skip});
61→    }
62→    std.debug.print("\x1b[0m\n{s}\n", .{BORDER});
63→
64→    std.process.exit(if (fail == 0) 0 else 1);
65→}
66→
67→fn extractTestName(name: []const u8) []const u8 {
68→    // Extract friendly name from "module.test.actual test name"
69→    var it = std.mem.splitScalar(u8, name, '.');
70→    while (it.next()) |value| {
71→        if (std.mem.eql(u8, value, "test")) {
72→            const rest = it.rest();
73→            return if (rest.len > 0) rest else name;
74→        }
75→    }
76→    return name;
77→}
