1087→fn buildMaskedClientFrameWithOpcode(
1088→    opcode: serval.WebSocketOpcode,
1089→    fin: bool,
1090→    payload: []const u8,
1091→    out: []u8,
1092→) ![]const u8 {
1093→    var header_buf: [serval.websocket.max_frame_header_size_bytes]u8 = undefined;
1094→    const header = serval.buildWebSocketFrameHeader(&header_buf, .{
1095→        .fin = fin,
1096→        .opcode = opcode,
1097→        .payload_len = payload.len,
1098→        .mask_key = WS_CLIENT_MASK,
1099→    }) orelse return error.BufferTooSmall;
1100→
1101→    if (out.len < header.len + payload.len) return error.BufferTooSmall;
1102→    @memcpy(out[0..header.len], header);
1103→    @memcpy(out[header.len..][0..payload.len], payload);
1104→
1105→    const payload_slice = out[header.len .. header.len + payload.len];
1106→    serval.applyWebSocketMask(payload_slice, WS_CLIENT_MASK);
1107→    return out[0 .. header.len + payload.len];
1108→}
