386→/// Read some bytes from source. Returns 0 on EOF.
387→/// Plain sockets use io.vtable.netRead (fiber-safe); TLS uses blocking read.
388→fn ioReadSome(socket: *Socket, io: Io, buf: []u8, side: Side) RelayFailure!u32 {
389→    assert(@intFromPtr(socket) != 0);
390→    assert(buf.len > 0);
391→
392→    return switch (socket.*) {
393→        .plain => |plain| {
394→            var read_bufs: [1][]u8 = .{buf};
395→            const n = io.vtable.netRead(io.userdata, plain.fd, &read_bufs) catch |err| {
396→                return mapNetError(side, err);
397→            };
398→            return @intCast(n);
399→        },
400→        .tls => {
401→            const n = socket.read(buf) catch |err| {
402→                return mapSocketError(side, err);
403→            };
404→            return n;
405→        },
406→    };
407→}
408→
409→/// Write all bytes to destination.
410→/// Plain sockets use io.vtable.netWrite (fiber-safe); TLS uses blocking write.
411→fn ioWriteAll(socket: *Socket, io: Io, data: []const u8, side: Side) RelayFailure!void {
412→    assert(@intFromPtr(socket) != 0);
413→    assert(data.len > 0);
414→
415→    return switch (socket.*) {
416→        .plain => |plain| {
417→            var sent: usize = 0;
418→            while (sent < data.len) {
419→                const pending = data[sent..];
420→                const write_slices = [_][]const u8{pending};
421→                const n = io.vtable.netWrite(io.userdata, plain.fd, &.{}, &write_slices, 1) catch |err| {
422→                    return mapNetError(side, err);
423→                };
424→                if (n == 0) return closeFailure(side);
425→                sent += n;
426→            }
427→        },
428→        .tls => {
429→            var sent: usize = 0;
430→            var iterations: u32 = 0;
431→            while (sent < data.len and iterations < Socket.max_write_iterations_count) : (iterations += 1) {
432→                const n = socket.write(data[sent..]) catch |err| {
433→                    return mapSocketError(side, err);
434→                };
435→                if (n == 0) return closeFailure(side);
436→                sent += n;
437→            }
438→            if (sent < data.len) return errorFailure(side);
439→        },
440→    };
441→}
