// -----------------------------------------------------------------------------
// Socket-backed forwardResponse tests
// Regression: forwardResponse previously silently dropped body bytes for
// responses without Content-Length or chunked encoding.
// These tests call forwardResponse() directly with real socketpairs.
// -----------------------------------------------------------------------------

const posix = std.posix;
const c = std.c;

/// Create a UNIX domain socketpair for testing.
/// Returns [upstream_fd, client_fd] or null on failure.
fn createTestSocketPair() ?[2]i32 {
    var fds: [2]i32 = undefined;
    const rc = c.socketpair(
        @intCast(posix.AF.UNIX),
        @intCast(posix.SOCK.STREAM),
        0,
        &fds,
    );
    if (rc != 0) return null;
    return fds;
}

fn writeAll(fd: i32, data: []const u8) void {
    var written: usize = 0;
    while (written < data.len) {
        const n = posix.write(fd, data[written..]) catch return;
