    try evented.init(std.testing.allocator, .{ .thread_limit = 0 });
    defer evented.deinit();
    const io = evented.io();

    const upstream_pair = try posix.socketpair(posix.AF.UNIX, posix.SOCK.STREAM, 0);
    defer posix.close(upstream_pair[0]);
