// -----------------------------------------------------------------------------

const posix = std.posix;

fn writeAll(fd: i32, data: []const u8) void {
    var written: usize = 0;
    while (written < data.len) {
        const n = posix.write(fd, data[written..]) catch return;
        written += n;
    }
